code.python:
def is_subsequence(s, t):
    i = 0
    for c in t:
        if i < len(s) and s[i] == c:
            i += 1
    return i == len(s)

code.javascript:
function isSubsequence(s, t) {
  let i = 0;
  for (const c of t) {
    if (i < s.length && s[i] === c) {
      i++;
    }
  }
  return i === s.length;
}

code.typescript:
function isSubsequence(s: string, t: string): boolean {
  let i = 0;
  for (const c of t) {
    if (i < s.length && s[i] === c) {
      i++;
    }
  }
  return i === s.length;
}
